                  </tbody>
                </table>
              ) : (
                <div className="h-full flex flex-col items-center justify-center py-12">
                  <CheckSquare className="w-12 h-12 text-emerald-300 mb-2" />
                  <p className="text-gray-500 font-bold">Tất cả học viên đã được vào khóa!</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <AddCourseModal
        isOpen={isAddModalOpen}
        onClose={() => {
          setIsAddModalOpen(false);
          setCourseToEdit(null);
        }}
        courseToEdit={courseToEdit}
      />

      {/* Detail Drawer */}
      <StudentDetailDrawer
        isOpen={!!selectedStudent}
        student={selectedStudent}
        onClose={() => setSelectedStudent(null)}
      />

      {/* Course Students List Drawer */}
      <CourseStudentsDrawer
        isOpen={!!selectedCourseForList}
        onClose={() => setSelectedCourseForList(null)}
        courseId={selectedCourseForList || ''}
        courseName={selectedCourseName}
        courseEndDate={selectedCourseEndDate}
      />

      <ConfirmModal
        isOpen={!!courseToDelete}
        onClose={() => setCourseToDelete(null)}
        onConfirm={executeDeleteCourse}
        title="Xác nhận xóa khóa học"
        message={`Bạn có chắc chắn muốn xóa khóa học "${courseToDelete?.name}" không? Hành động này không thể hoàn tác và mọi dữ liệu liên quan sẽ bị mất.`}
        type="danger"
        confirmText="Xác nhận xóa"
      />
    </div>
  );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import {
  Calendar,
  Plus,
  Search,
  Filter,
  AlertCircle,
  Clock,
  CheckCircle2,
  MapPin,
  Trash2,
  Edit3,
  Loader2,
  User,
} from 'lucide-react';
import ScheduleModal from '@/src/components/schedules/ScheduleModal';
import ConfirmModal from '@/src/components/shared/ConfirmModal';
import { toast } from 'sonner';
import { useAuth } from '@/src/context/AuthContext';
import { getLessonsByTeacher, deleteLesson } from '@/src/services/lessonService';
import { getExamBatches, deleteExamBatch } from '@/src/services/examBatchService';

interface ScheduleEvent {
  id: string;
  type: 'exam' | 'practice';
  teachingType: 'theory' | 'practice';
  date: string;
  actualStartTime: Date;
  actualEndTime: Date;
  displayDate: string;
  month: string;
  day: string;
  title: string;
  time: string;
  location: string;
  status: string;
  color: string;
  isNight?: boolean;
  km?: number;
  studentName?: string;
  raw: any;
}

export default function SchedulesPage() {
  const { user } = useAuth();
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [filterType, setFilterType] = useState('all');
  const [isDeleting, setIsDeleting] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<ScheduleEvent | null>(null);
  const [events, setEvents] = useState<ScheduleEvent[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [viewDate, setViewDate] = useState(new Date());

  const fetchEvents = useCallback(async () => {
    if (!user?.id) return;
    setIsLoading(true);
    try {
      const [lessonsRes, examsRes] = await Promise.all([
        getLessonsByTeacher(user.id, 1, 50),
        getExamBatches({ page: 1, limit: 50 }),
      ]);

      const lessonList =
        lessonsRes.data?.docs || lessonsRes.data?.data || (Array.isArray(lessonsRes.data) ? lessonsRes.data : []);
      const normalizedLessons: ScheduleEvent[] = lessonList.map((l: any) => {
        const startDate = new Date(l.start_time);
        const endDate = new Date(l.end_time || new Date(startDate.getTime() + 3 * 60 * 60 * 1000));
        const student = l.student_id;
        const studentName = student ? `HV: ${student.last_name} ${student.first_name}` : '';

        return {
          id: l._id,
          type: 'practice' as const,
          teachingType: l.category === 'theory' ? 'theory' : 'practice',
          date: l.start_time,
          actualStartTime: startDate,
          actualEndTime: endDate,
          displayDate: startDate.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' }),
          day: startDate.getDate().toString(),
          month: (startDate.getMonth() + 1).toString(),
          title: l.name,
          studentName: student ? `${student.last_name || ''} ${student.first_name || ''}`.trim() : '',
          time: `${startDate.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}`,
          location: l.stadium_id?.name || l.pickup_point || 'Cơ sở chính',
          status: l.status === 'completed' ? 'Hoàn thành' : 'Sắp tới',
          color: l.status === 'completed' ? 'emerald' : 'indigo',
          isNight: l.is_night_course,
          km: l.km,
          raw: l,
        };
      });

      const examListList =
        examsRes.data?.docs || examsRes.data?.data || (Array.isArray(examsRes.data) ? examsRes.data : []);
      const normalizedExams: ScheduleEvent[] = examListList.map((e: any) => {
        const startDate = new Date(e.examDate);
        const endDate = new Date(startDate.getTime() + 8 * 60 * 60 * 1000); // Default to 8h exam
        return {
          id: e._id,
          type: 'exam' as const,
          teachingType: 'practice' as const,
          date: e.examDate,
          actualStartTime: startDate,
          actualEndTime: endDate,
          displayDate: startDate.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' }),
          day: startDate.getDate().toString(),
          month: (startDate.getMonth() + 1).toString(),
          title: e.name,
          time: 'Cả ngày',
          location: e.venue,
          status: e.status === 'upcoming' ? 'Sắp diễn ra' : 'Đã xác nhận',
          color: e.status === 'upcoming' ? 'orange' : 'primary',
          raw: e,
        };
      });

      const combined = [...normalizedLessons, ...normalizedExams].sort(
        (a, b) => a.actualStartTime.getTime() - b.actualStartTime.getTime(),
      );

      setEvents(combined);
    } catch (error) {
      console.error('Fetch error:', error);
      toast.error('Không thể tải lịch trình. Vui lòng thử lại.');
    } finally {
      setIsLoading(false);
    }
  }, [user?.id]);

  useEffect(() => {
    fetchEvents();
  }, [fetchEvents]);

  const handleDelete = async () => {
    if (!selectedEvent) return;
    try {
      if (selectedEvent.type === 'practice') {
        await deleteLesson(selectedEvent.id);
      } else {
        await deleteExamBatch(selectedEvent.id);
      }
      toast.success('Đã xóa sự kiện khỏi lịch!');
      fetchEvents();
    } catch (error) {
      toast.error('Lỗi khi xóa sự kiện');
    } finally {
      setIsDeleting(false);
    }
  };

  const filteredEvents = events.filter((e) => {
    const d = new Date(e.date);
    const dateMatch =
      d.getDate() === selectedDate.getDate() &&
      d.getMonth() === selectedDate.getMonth() &&
      d.getFullYear() === selectedDate.getFullYear();

    if (!dateMatch) return false;

    if (filterType === 'all') return true;
    if (filterType === 'theory') return e.teachingType === 'theory';
    if (filterType === 'practice') return e.teachingType === 'practice' && e.type !== 'exam';
    if (filterType === 'exam') return e.type === 'exam';
    return true;
  });

  const formattedSelectedDate = selectedDate.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' });

  return (
    <div className="flex flex-col gap-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl sm:text-3xl font-black text-gray-900 tracking-tight leading-tight uppercase">
            Lịch Đào Tạo & Sát Hạch
          </h2>
          <p className="text-gray-500 font-bold uppercase tracking-widest text-[10px] mt-1.5 opacity-70">
            Lịch học thực hành và các đợt sát hạch
          </p>
        </div>
        <button
          onClick={() => setIsAddModalOpen(true)}
          className="flex items-center justify-center gap-2 px-8 py-2.5 bg-indigo-600 text-white font-black rounded-xl shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all active:scale-95 uppercase tracking-widest text-[11px]"
        >
          <Plus className="w-4 h-4" />
          Lên lịch mới
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Col - Mini Calendar & Stats */}
        <div className="flex flex-col gap-6">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col gap-6 hover:shadow-xl hover:shadow-indigo-600/5 transition-all">
            <div className="flex items-center justify-between">
              <h3 className="font-black text-gray-900 uppercase tracking-tight">
                Tháng {viewDate.getMonth() + 1}, {viewDate.getFullYear()}
              </h3>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => {
                    const now = new Date();
                    setViewDate(now);
                    setSelectedDate(now);
                  }}
                  className="px-3 py-1.5 text-[10px] font-black uppercase tracking-widest text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-lg transition-all mr-2 border border-indigo-100"
                >
                  Hôm nay
                </button>
                <button
                  onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1))}
                  className="w-9 h-9 flex items-center justify-center rounded-xl bg-gray-50 hover:bg-indigo-50 text-gray-400 hover:text-indigo-600 border border-gray-100 transition-all font-black"
                >
                  &lt;
                </button>
                <button
                  onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1))}
                  className="w-9 h-9 flex items-center justify-center rounded-xl bg-gray-50 hover:bg-indigo-50 text-gray-400 hover:text-indigo-600 border border-gray-100 transition-all font-black"
                >
                  &gt;
                </button>
              </div>
            </div>
            {/* Dynamic Calendar Grid */}
            <div className="grid grid-cols-7 gap-1 text-center text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">
              <div>T2</div>
              <div>T3</div>
              <div>T4</div>
              <div>T5</div>
              <div>T6</div>
              <div>T7</div>
              <div>CN</div>
            </div>
            <div className="grid grid-cols-7 gap-2 text-xs text-center font-bold">
              {/* Padding for the start of the month */}
              {Array.from({ length: (new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() + 6) % 7 }).map(
                (_, i) => (
                  <div key={`pad-${i}`} className="aspect-square" />
                ),
              )}

              {/* Actual days of the month */}
              {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate() }).map(
                (_, i) => {
                  const day = i + 1;
                  const isSelected =
                    selectedDate.getDate() === day &&
                    selectedDate.getMonth() === viewDate.getMonth() &&
                    selectedDate.getFullYear() === viewDate.getFullYear();
                  const hasEvents = events.some((e) => {
                    const d = new Date(e.date);
                    return (
                      d.getDate() === day &&
                      d.getMonth() === viewDate.getMonth() &&
                      d.getFullYear() === viewDate.getFullYear()
                    );
                  });

                  return (
                    <div
                      key={day}
                      onClick={() => setSelectedDate(new Date(viewDate.getFullYear(), viewDate.getMonth(), day))}
                      className={`aspect-square flex flex-col items-center justify-center rounded-xl cursor-pointer transition-all border relative ${
                        isSelected
                          ? 'bg-indigo-600 text-white font-black shadow-lg shadow-indigo-600/30 border-transparent scale-110'
                          : 'hover:bg-indigo-50 hover:text-indigo-600 border-transparent text-gray-500'
                      }`}
                    >
                      {day}
                      {hasEvents && !isSelected && (
                        <div className="absolute bottom-1 w-1 h-1 bg-indigo-400 rounded-full"></div>
                      )}
                    </div>
                  );
                },
              )}
            </div>
          </div>
        </div>

        {/* Right Col - Upcoming Events */}
        <div className="lg:col-span-2 flex flex-col gap-4">
          <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between">
            <h3 className="font-black text-gray-900 uppercase tracking-widest text-[11px] flex items-center gap-2">
              {isLoading ? (
                <Loader2 className="w-4 h-4 animate-spin text-indigo-600" />
              ) : (
                <Calendar className="w-4 h-4 text-indigo-600" />
              )}
              Lịch đào tạo ngày {formattedSelectedDate}
            </h3>
            <div className="flex items-center gap-2">
              {[
                { label: 'Tất cả', id: 'all', count: events.length },
                { label: 'Sát hạch', id: 'exam', count: events.filter((e) => e.type === 'exam').length },
                { label: 'Lý thuyết', id: 'theory', count: events.filter((e) => e.teachingType === 'theory').length },
                {
                  label: 'Thực hành',
                  id: 'practice',
                  count: events.filter((e) => e.teachingType === 'practice' && e.type !== 'exam').length,
                },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setFilterType(tab.id)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                    filterType === tab.id
                      ? 'bg-indigo-600 text-white border-transparent shadow-lg shadow-indigo-600/20'
                      : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-100 hover:text-indigo-600'
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>
          </div>

          {filteredEvents.length === 0 ? (
            <div className="bg-white p-12 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col items-center justify-center text-center">
              <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-4 border border-gray-100 shadow-inner">
                <Calendar className="w-10 h-10 text-gray-200" />
              </div>
              <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px] max-w-[200px]">
                Không có hoạt động đào tạo nào được ghi lại cho ngày này.
              </p>
              <button
                onClick={() => setIsAddModalOpen(true)}
                className="mt-6 px-6 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-100 transition-all border border-indigo-100"
              >
                + Lên lịch ngay
              </button>
            </div>
          ) : (
            <div className="flex flex-col gap-0 relative">
              {/* Timeline vertical track */}
              <div className="absolute left-[39px] top-6 bottom-6 w-0.5 bg-gray-50 z-0"></div>

              {filteredEvents.map((event, index) => {
                const now = new Date();
                const isLive =
                  now >= event.actualStartTime &&
                  now <= event.actualEndTime &&
                  now.toDateString() === event.actualStartTime.toDateString();

                return (
                  <div key={event.id} className="flex gap-6 items-start group relative pb-6 last:pb-0 z-10">
                    {/* Timeline node */}
                    <div
                      className={`mt-5 w-5 h-5 rounded-full border-4 bg-white z-20 transition-all ${
                        isLive
                          ? 'border-indigo-600 scale-125 shadow-lg shadow-indigo-600/30'
                          : event.status === 'Hoàn thành'
                            ? 'border-emerald-500'
                            : 'border-gray-200 group-hover:border-indigo-400'
                      }`}
                    >
                      {isLive && (
                        <div className="absolute inset-0 rounded-full bg-indigo-600 animate-ping opacity-20"></div>
                      )}
                    </div>

                    <div className="flex-1 bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:shadow-indigo-600/5 transition-all flex items-start gap-6 relative overflow-hidden group-hover:border-indigo-100">
                      <div className="absolute top-0 bottom-0 left-0 w-1 bg-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>

                      <div className="flex flex-col items-center justify-center bg-gray-50 rounded-2xl p-4 min-w-[80px] border border-gray-100 group-hover:bg-indigo-600 group-hover:border-transparent transition-all text-center group-hover:shadow-lg group-hover:shadow-indigo-600/30">
                        <span className="text-2xl font-black text-gray-900 group-hover:text-white leading-none mb-1">
                          {event.actualStartTime.getHours().toString().padStart(2, '0')}
                        </span>
                        <span className="text-[9px] font-black text-gray-400 group-hover:text-indigo-100 uppercase tracking-widest">
                          {event.actualStartTime.getMinutes().toString().padStart(2, '0')}
                        </span>
                      </div>

                      <div className="flex-1 flex flex-col justify-center">
                        <div className="flex items-center gap-2 flex-wrap">
                          <h4 className="font-black text-gray-900 text-lg group-hover:text-indigo-600 transition-colors tracking-tight uppercase truncate max-w-[250px]">
                            {event.title}
                          </h4>
                          {isLive && (
                            <span className="flex items-center gap-1.5 px-2 py-0.5 bg-rose-500 text-white text-[8px] font-black uppercase tracking-[0.2em] rounded-full animate-pulse shadow-sm shadow-rose-500/20">
                              <span className="w-1 h-1 bg-white rounded-full"></span> LIVE
                            </span>
                          )}
                          <span
                            className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border transition-all ${
                              event.teachingType === 'theory'
                                ? 'bg-sky-50 text-sky-600 border-sky-100'
                                : 'bg-indigo-50 text-indigo-600 border-indigo-100'
                            }`}
                          >
                            {event.teachingType === 'theory' ? 'Lý thuyết' : 'Thực hành'}
                          </span>
                          {event.isNight && (
                            <span className="flex items-center gap-1 px-2 py-0.5 bg-slate-900 text-slate-100 text-[8px] font-black uppercase tracking-widest rounded-lg border border-slate-800">
                              🌙 Đêm
                            </span>
                          )}
                        </div>
                        <div className="flex items-center gap-4 mt-2 flex-wrap">
                          <p className="text-xs font-bold text-gray-400 flex items-center gap-1.5">
                            <Clock className="w-3.5 h-3.5 text-indigo-400 opacity-60" /> {event.time}
                          </p>
                          <p className="text-xs font-bold text-gray-400 flex items-center gap-1.5">
                            <MapPin className="w-3.5 h-3.5 text-indigo-400 opacity-60" /> {event.location}
                          </p>
                          {event.studentName && (
                            <p className="text-xs font-bold text-indigo-600 flex items-center gap-1.5">
                              <User className="w-3.5 h-3.5 text-indigo-400" /> {event.studentName}
                            </p>
                          )}
                          {(event.km || 0) > 0 && (
                            <p className="text-xs font-bold text-amber-600 flex items-center gap-1.5">
                              <span className="p-0.5 bg-amber-100 rounded text-[10px]">🏁</span> {event.km}km
                            </p>
                          )}
                        </div>
                      </div>

                      <div className="flex flex-col items-end gap-3 min-w-[100px]">
                        <span
                          className={`px-3 py-1 text-[9px] font-black uppercase tracking-widest rounded-xl shadow-sm border transition-all ${
                            event.color === 'orange'
                              ? 'bg-amber-50 text-amber-600 border-amber-100'
                              : event.color === 'indigo'
                                ? 'bg-indigo-50 text-indigo-600 border-indigo-100'
                                : 'bg-emerald-50 text-emerald-600 border-emerald-100'
                          }`}
                        >
                          {event.status}
                        </span>
                        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              setSelectedEvent(event);
                              setIsEditModalOpen(true);
                            }}
                            className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all border border-gray-100 bg-white shadow-sm hover:shadow-indigo-600/10"
                            title="Sửa"
                          >
                            <Edit3 className="w-4 h-4" />
                          </button>
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              setSelectedEvent(event);
                              setIsDeleting(true);
                            }}
                            className="p-2 text-gray-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all border border-gray-100 bg-white shadow-sm hover:shadow-rose-600/10"
                            title="Xóa"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Modals */}
      <ScheduleModal
        isOpen={isAddModalOpen}
        onClose={() => setIsAddModalOpen(false)}
        onSuccess={fetchEvents}
        mode="add"
      />

      <ScheduleModal
        isOpen={isEditModalOpen}
        onClose={() => {
          setIsEditModalOpen(false);
          setSelectedEvent(null);
        }}
        onSuccess={fetchEvents}
        mode="edit"
        initialData={selectedEvent}
      />

      <ConfirmModal
        isOpen={isDeleting}
        onClose={() => setIsDeleting(false)}
        onConfirm={handleDelete}
        title="Xác nhận xóa lịch"
        message={`Bạn có chắc chắn muốn xóa sự kiện "${selectedEvent?.title}" khỏi lịch đào tạo không? Thao tác này không thể hoàn tác.`}
        confirmText="Xóa lịch"
        type="danger"
      />
    </div>
  );
}

