  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [isAddPaymentModalOpen, setIsAddPaymentModalOpen] = useState(false);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);

  const [payments, setPayments] = useState<any[]>([]);
  const [cities, setCities] = useState<any[]>([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [meta, setMeta] = useState<any>(null);
  const [stats, setStats] = useState<any>({
    total_received: 0,
    total_receivable: 0,
    total_debt: 0,
    debtor_count: 0,
    by_category: [],
  });
  const [isLoading, setIsLoading] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);

  const fetchPayments = async (page = 1) => {
    setIsLoading(true);
    try {
      const [res, statsRes, citiesRes] = await Promise.all([
        getPayments(page, LIMIT, { search: search.trim(), status: filterStatus }),
        getPaymentStats(),
        cities.length === 0 ? getCities() : Promise.resolve(null),
      ]);

      if (res.success && res.data) {
        setPayments(res.data.items || res.data.docs || res.data.data || []);
        setMeta(res.data.pagination || res.data.meta);
      }

      if (statsRes.success && statsRes.data) {
        setStats(statsRes.data);
      }

      if (citiesRes && citiesRes.success && citiesRes.data) {
        setCities(citiesRes.data);
      }
    } catch (error: any) {
      toast.error('Lỗi khi tải dữ liệu học phí');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchPayments(currentPage);
  }, [currentPage]);

  useEffect(() => {
    if (currentPage === 1) {
      fetchPayments(1);
    } else {
      setCurrentPage(1);
    }
  }, [search, filterStatus]);

  useEffect(() => {
    const handleRefresh = () => fetchPayments(1);
    window.addEventListener('refresh-student-list', handleRefresh);
    window.addEventListener('refresh-payment-list', handleRefresh);
    return () => {
      window.removeEventListener('refresh-student-list', handleRefresh);
      window.removeEventListener('refresh-payment-list', handleRefresh);
    };
  }, []);

  // Summary numbers from backend stats
  const totalIncome = stats.total_received;
  const totalDebt = stats.total_debt;
  const debtCount = stats.debtor_count;

  const displayed = payments;

  const openStudentDrawer = (item: any) => {
    const courseStudent = item.course_student_id || {};
    const studentUser = courseStudent.student_id?.user_id || {};
    const name = `${studentUser.last_name || ''} ${studentUser.first_name || ''}`.trim() || 'Ẩn danh';

    const studentProp = {
      id: courseStudent.student_id?._id,
      name: name,
      phone: studentUser.phone || '--',
      rank: courseStudent.course_id?.license_category_id?.name || 'B2',
      region: courseStudent.student_id?.region_id?.name || 'Nội thành',
      status: courseStudent.student_id?.status || '',
    };
    setSelectedStudent({ ...studentProp, _openTab: 'hocphi' });
  };

  const handleExport = async (type: 'basic' | 'premium' = 'basic') => {
    setIsExporting(true);
    setIsExportMenuOpen(false);
    try {
      const filters = { search, status: filterStatus };
      if (type === 'premium') {
        await exportPremiumPayments(filters);
      } else {
        await exportPayments(filters);
      }
      toast.success('Xuất dữ liệu Excel thành công');
    } catch (error) {
      toast.error('Lỗi khi xuất dữ liệu');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-2 duration-700">
      {/* Header bar */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-baseline gap-4 mb-2 animate-in fade-in slide-in-from-left duration-700">
        <div>
          <h2 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight leading-tight uppercase">
            Quản lý Học Phí
          </h2>
          <p className="text-gray-500 font-medium mt-1">Báo cáo tài chính và danh sách nợ phí</p>
        </div>
        <div className="flex items-center gap-3 w-full sm:w-auto relative">
          <div className="relative">
            <button
              onClick={() => setIsExportMenuOpen(!isExportMenuOpen)}
              disabled={isExporting}
              className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isExporting ? (
                <div className="w-4 h-4 border-2 border-indigo-600/20 border-t-indigo-600 rounded-full animate-spin" />
              ) : (
                <Download className="w-4 h-4" />
              )}
              <span className="hidden sm:inline">{isExporting ? 'Đang xuất...' : 'Xuất'}</span>
              <ChevronDown
                className={`w-4 h-4 transition-transform duration-200 ${isExportMenuOpen ? 'rotate-180' : ''}`}
              />
            </button>

            {isExportMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsExportMenuOpen(false)} />
                <div className="absolute right-0 mt-2 w-64 bg-white border border-gray-100 rounded-xl shadow-xl z-20 py-2 animate-in fade-in zoom-in-95 duration-200">
                  <button
                    onClick={() => handleExport('basic')}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 transition-colors text-left"
                  >
                    <Download className="w-4 h-4 text-gray-400" />
                    <div className="flex flex-col">
                      <span className="font-bold">Danh sách phiếu thu</span>
                      <span className="text-[10px] text-gray-400">Xuất danh sách hiển thị hiện tại</span>
                    </div>
                  </button>
                  <div className="h-px bg-gray-50 my-1" />
                  <button
                    onClick={() => handleExport('premium')}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-indigo-600 hover:bg-indigo-50/50 transition-colors text-left group"
                  >
                    <FileText className="w-4 h-4 text-indigo-400 group-hover:scale-110 transition-transform" />
                    <div className="flex flex-col">
                      <span className="font-bold">Báo cáo tài chính (Xịn)</span>
                      <span className="text-[10px] text-indigo-400/70">Đầy đủ 3 sheet, tổng quan & công nợ</span>
                    </div>
                  </button>
                </div>
              </>
            )}
          </div>
          <button
            onClick={() => setIsImportModalOpen(true)}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-emerald-200 text-emerald-600 font-bold rounded-xl shadow-sm hover:bg-emerald-50 transition-all active:scale-95 px-5"
          >
            <Upload className="w-4 h-4" /> Import Học phí
          </button>
          <button
            onClick={() => setIsAddPaymentModalOpen(true)}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-emerald-500 text-white font-bold rounded-xl shadow-lg shadow-emerald-500/25 hover:bg-emerald-600 transition-all active:scale-95"
          >
            <DollarSign className="w-4 h-4" /> Thu tiền
          </button>
        </div>
      </div>

      {/* Cards Row 1 — big revenue card + 3 stat cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {/* Hero card */}
        <div className="md:col-span-1 bg-gradient-to-br from-primary to-indigo-600 p-6 rounded-2xl shadow-lg shadow-primary/20 text-white flex flex-col gap-3 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <CreditCard className="w-20 h-20" />
          </div>
          <span className="text-xs font-bold text-white/70 uppercase tracking-wider relative z-10">
            Tổng doanh thu kỳ này
          </span>
          <h3 className="text-3xl font-black relative z-10">{fmt(totalIncome)}</h3>
          <span className="flex items-center gap-1 text-xs font-bold bg-white/20 px-2 py-1 rounded-lg w-fit backdrop-blur-sm relative z-10">
            <ArrowUpRight className="w-3 h-3" /> +15.3% so với tháng trước
          </span>
        </div>

        <StatCard
          label="Tổng doanh số (Học phí)"
          value={fmt(stats.total_receivable)}
          icon={<DollarSign className="w-5 h-5 text-indigo-500" />}
          color="primary"
        />
        <StatCard
          label="Thực thu thực tế"
          value={fmt(totalIncome)}
          icon={<DollarSign className="w-5 h-5" />}
          color="success"
        />
        <StatCard
          label="Tổng nợ cần thu"
          value={fmt(totalDebt)}
          icon={<AlertTriangle className="w-5 h-5" />}
          color="danger"
          trend="-5%"
          trendType="positive"
        />

        {/* New card: Số HV còn nợ */}
        <div
          onClick={() => setFilterStatus('all_debt')}
          className="bg-white border border-gray-100 rounded-2xl p-5 flex items-center gap-4 shadow-sm hover:shadow-md transition-shadow cursor-pointer"
        >
          <div className="w-12 h-12 rounded-xl bg-rose-50 flex items-center justify-center shrink-0">
            <Users className="w-5 h-5 text-rose-600" />
          </div>
          <div className="flex flex-col">
            <span className="text-2xl font-black text-rose-600">{debtCount}</span>
            <span className="text-xs font-semibold text-gray-500 mt-0.5 leading-tight">Số học sinh còn nợ</span>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <TuitionCharts stats={stats} isLoading={isLoading} />

      {/* Grouped Summary Section */}
      {!isLoading && <FinanceSummaryTable stats={stats} />}

      {/* Toolbar */}
      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col md:flex-row gap-3 justify-between items-start md:items-center">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Tìm mã phiếu, tên, SĐT..."
            className="w-full pl-9 pr-4 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all"
          />
        </div>
        <div className="flex flex-wrap gap-2">
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="px-3 py-2 bg-white border border-gray-200 rounded-lg text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 cursor-pointer"
          >
            <option value="">Tất cả trạng thái nợ</option>
            <option value="done">Hoàn thành</option>
            <option value="partial">Đóng 1 phần</option>
            <option value="debt">Còn nợ (0đ)</option>
            <option value="all_debt">Tất cả còn nợ</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white border border-gray-100 shadow-card rounded-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50/70 border-b border-gray-100 text-[11px] uppercase tracking-wider text-gray-500 font-extrabold">
                <th className="px-6 py-4">Mã phiếu</th>
                <th className="px-6 py-4">Học viên</th>
                <th className="px-6 py-4 whitespace-nowrap">Giai đoạn</th>
                <th className="px-6 py-4 whitespace-nowrap">Đã đóng</th>
                <th className="px-6 py-4 whitespace-nowrap">Tổng phải đóng</th>
                <th className="px-6 py-4 whitespace-nowrap text-center">Còn nợ</th>
                <th className="px-6 py-4 text-center">Trạng thái</th>
                <th className="px-6 py-4 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {displayed.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-6 py-16 text-center text-gray-400 font-semibold">
                    Không tìm thấy kết quả phù hợp.
                  </td>
                </tr>
              ) : (
                displayed.map((item) => {
                  const courseStudent = item.course_student_id || {};
                  const student = courseStudent.student_id?.user_id || {};
                  const debt = (courseStudent.fee || 0) - (courseStudent.paid_fee || 0);
                  const name = `${student.last_name || ''} ${student.first_name || ''}`.trim() || 'Ẩn danh';

                  return (
                    <tr key={item._id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-6 py-4 font-bold text-sm text-gray-500 font-mono">
                        {item.is_tuition_account
                          ? 'ACC-' + item._id.substring(item._id.length - 6).toUpperCase()
                          : item._id.substring(item._id.length - 6).toUpperCase()}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                          <span className="font-extrabold text-gray-900 text-sm">{name}</span>
                          <div className="flex items-center gap-1.5 mt-0.5">
                            <span className="px-1.5 py-0.5 bg-blue-50 text-blue-700 text-[10px] font-black border border-blue-100 rounded">
                              {courseStudent.course_id?.name || 'B2'}
                            </span>
                            <span className="text-[11px] text-gray-400">{student.phone || '--'}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        {(item as any).latest_stage ? (
                          <span className="px-2 py-1 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg text-[10px] font-black uppercase">
                            {(item as any).latest_stage}
                          </span>
                        ) : (
                          <span className="text-[10px] text-gray-300 font-bold italic">Chưa ghi nhận</span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-emerald-600 font-bold">{fmt(item.received_fee)}</td>
                      <td className="px-6 py-4 text-gray-700 font-semibold">{fmt(courseStudent.fee)}</td>
                      <td className="px-6 py-4 text-center">
                        {debt > 0 ? (
                          <span className="font-black text-rose-600 text-sm">{fmt(debt)}</span>
                        ) : (
                          <span className="text-emerald-500 font-black text-sm">—</span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span
                          className={`px-2 py-1 rounded-lg text-[10px] font-bold border ${
                            debt <= 0
                              ? statusMeta.done.cls
                              : courseStudent.paid_fee > 0
                                ? statusMeta.partial.cls
                                : statusMeta.debt.cls
                          }`}
                        >
                          {debt <= 0
                            ? statusMeta.done.label
                            : courseStudent.paid_fee > 0
                              ? statusMeta.partial.label
                              : statusMeta.debt.label}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => openStudentDrawer(item)}
                          title="Xem chi tiết học phí"
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-white border border-indigo-200 text-indigo-600 hover:bg-indigo-50 hover:border-indigo-300 transition-colors rounded-lg font-bold text-[11px] shadow-sm group"
                        >
                          <Eye className="w-3.5 h-3.5 group-hover:scale-110 transition-transform" /> Xem
                        </button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>

        {/* Footer with Pagination */}
        <div className="flex flex-col sm:flex-row items-center justify-between px-6 py-4 border-t border-gray-100 gap-4">
          <div className="flex flex-col gap-1">
            <span className="text-sm font-medium text-gray-500">
              Hiển thị <strong className="text-gray-900">{displayed.length}</strong> {meta ? `/ ${meta.total}` : ''}{' '}
              phiếu
            </span>
            <div className="flex items-center gap-2 text-[11px] font-bold text-gray-400">
              Tổng thu hiển thị:&nbsp;
              <span className="text-emerald-600 font-black text-xs">
                {fmt(displayed.reduce((s, r) => s + (r.received_fee || 0), 0))}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
              disabled={currentPage === 1 || isLoading}
              className="px-3 py-1.5 border border-gray-200 rounded-lg text-xs font-bold text-gray-600 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              Trước
            </button>
            <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-50 rounded-lg border border-gray-100">
              <span className="text-xs font-black text-primary">{currentPage}</span>
              <span className="text-xs font-bold text-gray-400">/</span>
              <span className="text-xs font-bold text-gray-500">{meta?.total_pages || 1}</span>
            </div>
            <button
              onClick={() => setCurrentPage((p) => Math.min(meta?.total_pages || 1, p + 1))}
              disabled={currentPage === (meta?.total_pages || 1) || isLoading}
              className="px-3 py-1.5 border border-gray-200 rounded-lg text-xs font-bold text-gray-600 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              Sau
            </button>
          </div>
        </div>
      </div>

      <AddPaymentModal
        isOpen={isAddPaymentModalOpen}
        onClose={() => setIsAddPaymentModalOpen(false)}
        onSuccess={() => fetchPayments(1)}
      />

      <ImportTuitionModal
        isOpen={isImportModalOpen}
        onClose={() => setIsImportModalOpen(false)}
        onSuccess={() => fetchPayments(1)}
      />

      {/* Student detail drawer — open on Học phí tab */}
      <StudentDetailDrawer
        isOpen={!!selectedStudent}
        student={selectedStudent}
        onClose={() => setSelectedStudent(null)}
        defaultTab="hocphi"
      />
    </div>
  );
}

'use client';

import React, { useState, useRef, useEffect } from 'react';
import { 
  MessageSquare, 
  Search, 
  Filter, 
  ArrowDownToLine, 
  CheckCircle2, 
  Clock, 
  AlertCircle,
  MoreVertical,
  Eye,
  Pencil,
  Trash2,
  X,
  Save,
  User,
  Calendar,
  Tag,
  Loader2
} from 'lucide-react';
import { toast } from 'sonner';
import ConfirmModal from '@/src/components/shared/ConfirmModal';
import { getAllSupportRequests, updateSupportRequest, deleteSupportRequest } from '@/src/services/supportRequestService';

export default function SupportRequestsPage() {
  const [tickets, setTickets] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('Tất cả');

  // Modal states
  const [viewTicket, setViewTicket] = useState<any>(null);
  const [editTicket, setEditTicket] = useState<any>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);

  const fetchTickets = async () => {
    try {
      setIsLoading(true);
      const res = await getAllSupportRequests({});
      if (res.success && res.data) {
        const fetched = res.data.docs.map((d: any) => ({
          id: d._id,
          topic: d.topic,
          title: d.title,
          sender: (d.sender_id?.full_name || 'Không rõ') + (d.sender_role ? ` (${d.sender_role})` : ''),
          priority: d.priority,
          status: d.status,
          date: d.created_at,
          description: d.description,
        }));
        setTickets(fetched);
      }
    } catch (e) {
      console.error(e);
      toast.error('Không thể truy xuất dữ liệu từ máy chủ.');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchTickets();
  }, []);

  // Close dropdown on outside click (simple implementation)
  useEffect(() => {
    const handleClick = () => setActiveDropdown(null);
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, []);

  const filteredTickets = tickets.filter(ticket => {
    const matchesSearch = ticket.topic.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          ticket.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          ticket.sender.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'Tất cả' || ticket.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleDeleteConfirm = async () => {
    if (deleteId) {
      try {
        await deleteSupportRequest(deleteId);
        setTickets(tickets.filter(t => t.id !== deleteId));
        toast.success('Đã xóa yêu cầu hỗ trợ thành công!', { style: { background: '#10B981', color: '#fff' } });
      } catch (e) {
        toast.error('Lỗi khi xóa bảng ghi!');
      } finally {
        setDeleteId(null);
      }
    }
  };

  const handleEditSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editTicket) {
      try {
        await updateSupportRequest(editTicket.id, {
          status: editTicket.status,
          priority: editTicket.priority,
          title: editTicket.title
        });
        setTickets(tickets.map(t => t.id === editTicket.id ? editTicket : t));
        toast.success('Cập nhật thông tin thành công!');
        setEditTicket(null);
      } catch (e) {
        toast.error('Lỗi khi cập nhật trạng thái');
      }
    }
  };

  const getPriorityStyle = (priority: string) => {
    switch (priority) {
      case 'Nghiêm trọng': return 'bg-rose-100 text-rose-700 border-rose-200';
      case 'Cao': return 'bg-orange-100 text-orange-700 border-orange-200';
      case 'Bình thường': return 'bg-blue-100 text-blue-700 border-blue-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case 'Mới': return 'text-amber-600 bg-amber-50 border-amber-200';
      case 'Đang xử lý': return 'text-blue-600 bg-blue-50 border-blue-200';
      case 'Hoàn thành': return 'text-emerald-600 bg-emerald-50 border-emerald-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in duration-700 pb-10">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight">Cổng Hỗ Trợ Kỹ Thuật</h1>
          <p className="text-gray-500 font-medium mt-1">Tiếp nhận và xử lý yêu cầu hỗ trợ từ Giáo viên & Nhân viên</p>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
