'use client';

import React, { createContext, useContext, useState, useEffect, useMemo, useCallback } from 'react';
import { apiClient } from '@/src/services/api';

interface User {
  id: string;
  username: string;
  role: string;
  first_name: string;
  last_name: string;
  email: string;
  phone: string;
  address?: string;
  image?: string;
  bio?: string;
  created_at?: string;
}

interface AuthContextType {
  token: string | null;
  user: User | null;
  setToken: (token: string | null, userData?: User | null) => void;
  setUser: (user: User | null) => void;
  refreshUser: () => Promise<void>;
  isAuthenticated: boolean;
  loading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [token, setToken] = useState<string | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchUser = useCallback(async (_authToken: string) => {
    try {
      const res = await apiClient('/auth/me', { cacheTtlMs: 10000 });
      if (res.success) {
        const userData = {
          ...res.data,
          id: res.data.id || res.data._id,
        };
        setUser(userData);
        return userData;
      }
      throw new Error(res.message);
    } catch (error) {
      localStorage.removeItem('token');
      setToken(null);
      setUser(null);
      throw error;
    }
  }, []);

  // Initial authentication bootup
  useEffect(() => {
    const initAuth = async () => {
      const savedToken = typeof window !== 'undefined' ? localStorage.getItem('token') : null;

      if (!savedToken) {
        setLoading(false);
        return;
      }

      setToken(savedToken);

      try {
        await fetchUser(savedToken);
      } catch (error) {
        // Handled in fetchUser
      } finally {
        setLoading(false);
      }
    };

    initAuth();
  }, [fetchUser]); // Run only once on mount

  const refreshUser = useCallback(async () => {
    const savedToken = typeof window !== 'undefined' ? localStorage.getItem('token') : null;
    if (savedToken) {
      await fetchUser(savedToken);
    }
  }, [fetchUser]);

  const contextValue = useMemo(
    () => ({
      token,
      user,
      setToken: (newToken: string | null, userData?: User | null) => {
        if (newToken) {
          localStorage.setItem('token', newToken);
          if (userData) setUser(userData);
        } else {
          localStorage.removeItem('token');
          setUser(null);
        }
        setToken(newToken);
        if (newToken && userData) setLoading(false);
      },
      setUser,
      refreshUser,
      isAuthenticated: !!token,
      loading,
    }),
    [token, user, refreshUser, loading],
  );

  return <AuthContext.Provider value={contextValue}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

