import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

const Button: React.FC<ButtonProps> = ({
  children,
  variant = 'primary',
  size = 'md',
  fullWidth = false,
  className = '',
  ...props
}) => {
  const baseStyles =
    'inline-flex items-center justify-center font-medium transition-all focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed rounded-md';

  const variants = {
    primary: 'bg-primary text-white hover:bg-primary/90 shadow-sm shadow-primary/20',
    secondary: 'bg-primary-soft text-primary hover:bg-primary-100',
    outline: 'border border-gray-200 bg-transparent hover:bg-gray-50 text-gray-700',
    ghost: 'bg-transparent hover:bg-gray-100 text-gray-600',
    danger: 'bg-danger text-white hover:bg-danger/90 shadow-sm shadow-danger/20',
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-4 py-2 text-sm',
    lg: 'px-6 py-3 text-base',
  };

  const widthStyle = fullWidth ? 'w-full' : '';

  return (
    <button className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${widthStyle} ${className}`} {...props}>
      {children}
    </button>
  );
};

export default Button;

import React from 'react';

interface StatCardProps {
  label: string;
  value: string | number;
  icon?: React.ReactNode;
  trend?: string;
  trendType?: 'positive' | 'negative' | 'neutral';
  color?: 'primary' | 'success' | 'warning' | 'danger' | 'info' | 'purple' | 'indigo' | 'orange' | 'teal' | 'sky';
}

const StatCard: React.FC<StatCardProps> = ({ label, value, icon, trend, trendType = 'neutral', color = 'primary' }) => {
  const colorStyles = {
    primary: 'text-primary bg-primary-soft',
    success: 'text-emerald-500 bg-emerald-50',
    warning: 'text-amber-500 bg-amber-50',
    danger: 'text-rose-500 bg-rose-50',
    info: 'text-blue-500 bg-blue-50',
    purple: 'text-purple-500 bg-purple-50',
    indigo: 'text-indigo-500 bg-indigo-50',
    orange: 'text-orange-500 bg-orange-50',
    teal: 'text-teal-500 bg-teal-50',
    sky: 'text-sky-500 bg-sky-50',
  };

  const trendStyles = {
    positive: 'text-emerald-500',
    negative: 'text-rose-500',
    neutral: 'text-gray-400',
  };

  return (
    <div className="bg-surface p-6 rounded-card shadow-card border border-gray-100/30 flex flex-col gap-4 transition-all hover:shadow-lg hover:-translate-y-1 group">
      <div className="flex items-center justify-between">
        <span className="text-sm font-bold text-gray-400 uppercase tracking-tight">{label}</span>
        {icon && (
          <div
            className={`${colorStyles[color]} p-2.5 rounded-xl transition-transform group-hover:scale-110 shadow-sm`}
          >
            {icon}
          </div>
        )}
      </div>

      <div className="flex items-baseline justify-between gap-2 mt-auto">
        <h3 className="text-3xl font-extrabold text-gray-900 leading-none tabular-nums">{value}</h3>
        {trend && (
          <div
            className={`flex items-center gap-1 px-2 py-1 rounded-lg text-xs font-bold bg-white border border-gray-50 shadow-sm ${trendStyles[trendType]}`}
          >
            {trend}
          </div>
        )}
      </div>
    </div>
  );
};

export default StatCard;

