#!/usr/bin/env python3
import json
import requests
import base64

AUTH_EMAIL = "ninhkhuongpl7@gmail.com"
AUTH_TOKEN = "ATATT3xFfGF0bFjmIN6IPHwDzRChO8oMe5XAaA6dheluE8J2eUTNZHLgprik7oLx-vNnZsNVCb4cAAjziLDb27lKFHU2_RTgdeuv8zMkaPR-or2gSJQjHp8TMmOtI53F6MauTeaXX5Tg4gdMYyJ2nUKI-2HSMvK4TLkXLmKSKrdGrOpNDLRgMxA=8865492F"

auth = base64.b64encode(f"{AUTH_EMAIL}:{AUTH_TOKEN}".encode()).decode()
headers = {
    "Authorization": f"Basic {auth}",
    "Content-Type": "application/json"
}

def get_current_version(page_id):
    url = f"https://dtlx.atlassian.net/wiki/rest/api/content/{page_id}"
    resp = requests.get(url, headers=headers, timeout=30)
    data = resp.json()
    return data.get('version', {}).get('number', 1)

def update_page(page_id, title, html_content, current_version):
    url = f"https://dtlx.atlassian.net/wiki/rest/api/content/{page_id}"
    payload = {
        "type": "page",
        "version": {"number": current_version + 1},
        "title": title,
        "body": {
            "storage": {
                "value": html_content,
                "representation": "storage"
            }
        }
    }
    resp = requests.put(url, headers=headers, json=payload, timeout=30)
    data = resp.json()

    if resp.status_code == 200 and data.get('id'):
        return f"OK - Version: {data['version']['number']}"
    else:
        return f"ERROR ({resp.status_code}): {str(data)[:100]}"

# Load payloads
pages = {}
for i in range(1, 11):
    try:
        with open(f'/root/.openclaw/workspaces2/projects/ahv-qlhv-fe/doc-payload{i}.json', 'r') as f:
            pages[i] = json.load(f)
    except:
        pass

# Update existing pages
existing_pages = {
    1: "130744353",   # FE-1
    2: "130842761",   # FE-2
    3: "130744399",   # FE-3
    4: "130744414",   # FE-4
    5: "130744429",   # FE-5
}

for i in sorted(existing_pages.keys()):
    page_id = existing_pages[i]
    if i not in pages:
        print(f"FE-{i}: Payload not found")
        continue

    payload = pages[i]
    title = payload.get('title', f'FE-{i}')
    content = payload.get('body', {}).get('storage', {}).get('value', '')

    current_ver = get_current_version(page_id)
    print(f"Updating FE-{i} (ID={page_id}, v{current_ver})...")
    result = update_page(page_id, title, content, current_ver)
    print(f"  -> {result}")

